module top_module(
	input  wire clk,

	input  wire re,
	input  wire [8:0] rdaddr,
	output reg  [7:0] dataout,

	input  wire we,
	input  wire [8:0] wraddr,
	input  wire [7:0] datain
);reg [7:0] unused_mem[0:511]; 



	always @(posedge clk)
	if( re )
		dataout <= unused_mem[rdaddr];

	always @(posedge clk)
	if( we )
		unused_mem[wraddr] <= datain;

endmodule
